  ('diplomatic-9e854390-moex-00056', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '關於人身自由之限制，下列敘述何者錯誤？', '["對於行政執行法所為管收，受管收人如有不服，可向所在地地方法院聲請提審", "依入出國及移民法對外國人之暫時收容，毋須將受收容人移送法院進行裁定", "任何人受到法院以外之機關逮捕拘禁時，包含本人及其他任何人均可聲請提審", "憲法第8條第2項規定「至遲於24小時內移送」應自人民實際失去人身自由的時間點起算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
