  ('diplomatic-9e854390-moex-00059', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '憲法法庭為暫時處分之裁定，應經下列何種方式為之？', '["大法官現有總額3分之2以上參與評議，大法官現有總額過半數同意", "大法官現有總額3分之2以上參與評議，參與評議大法官過半數同意", "大法官現有總額過半數參與評議，大法官現有總額過半數同意", "大法官現有總額過半數參與評議，參與評議大法官過半數同意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00060', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依憲法法庭判決，關於名譽權與言論自由之保障，下列敘述何者錯誤？', '["強制公開道歉非僅涉及客觀事實陳述之表意，也涉及價值立場自主決定等高價值言論內容之干預", "強制公開道歉之手段係禁止沉默、強制表態，人民甚至必須發表自我否定之言論，其對言論自由之 干預強度較國家禁制人民積極表意之情形更高", "以判決命「法人」之加害人公開道歉，因無涉人性尊嚴之侵害，未牴觸憲法保障人民言論自由之意 旨，合憲", "以強制公開道歉作為回復名譽適當處分之手段是否合憲，憲法法庭採取嚴格審查標準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00061', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '有關憲法上服兵役義務，下列敘述何者錯誤？', '["徵兵必須依立法院通過之法律為之", "服兵役之重要事項須考量國家安全及社會發展需要", "宗教信仰如有要求信徒不得從軍，則要求服兵役之法律將因牴觸宗教自由之保障而違憲", "服兵役義務無違反人性尊嚴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00062', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '某甲就讀高雄市某私立國中，因其在社會課的討論課堂上嚴厲評論國內時事，違反學校「禁止於校園 內談論政治事件」的規定而遭記過一支，並且被禁止繼續參與課堂討論。某甲不服，主張此一懲戒已 經侵犯其言論自由以及受國民教育的權利。請問某甲應如何提起救濟？', '["逕行向普通法院提起民事訴訟", "僅得向高雄市政府教育局提起訴願", "提起申訴與訴願程序後，得向行政法院提起訴訟", "特別權力關係下，無任何救濟程序"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00063', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '有關我國總統之職權，下列敘述何者正確？', '["總統為避免國家或人民遭遇緊急危難或應付財政經濟上重大變故，得經行政院會議之決議發布緊急 命令。但在立法院休會期間，須於發布命令後1個月內提交立法院追認", "總統於立法院通過對行政院院長之不信任案後10日內，經諮詢行政院院長後，得宣告解散立法院。 但總統於戒嚴期間內，不得解散立法院", "總統依法公布法律，須經行政院院長之副署，或行政院院長及有關部會首長之副署", "總統享有對行政院院長、司法院正、副院長及大法官、監察院正、副院長、考試院正、副院長之提 名權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00064', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依據憲法訴訟法規定，下列敘述何者錯誤？', '["法院僅得就法律位階法規範牴觸憲法聲請憲法審查", "少數立法委員僅得就法律位階法規範牴觸憲法聲請憲法審查", "人民不得就裁判牴觸憲法聲請憲法審查", "鄉（鎮、市）不得就中央法規範牴觸憲法聲請憲法審查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
